+#!/usr/bin/env -S gjs -m
+import { describe, it, assertEqual, assertTrue, assertFalse, assertNull, assertDeepEqual, printResults } from './run.js';
+import { FocusRankList } from '../lib/focusTracker.js';
+
+describe('FocusRankList', () => {
+    it('tracks focus order', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('c');
+        assertDeepEqual(list.getRanks(), ['c', 'b', 'a']);
+    });
+
+    it('moves refocused window to top', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('a');
+        assertDeepEqual(list.getRanks(), ['a', 'b']);
+    });
+
+    it('removes window from list', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.remove('a');
+        assertDeepEqual(list.getRanks(), ['b']);
+    });
+
+    it('returns rank for a window', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('c');
+        assertEqual(list.getRank('c'), 0);
+        assertEqual(list.getRank('b'), 1);
+        assertEqual(list.getRank('a'), 2);
+    });
+
+    it('returns -1 for unknown window', () => {
+        const list = new FocusRankList();
+        assertEqual(list.getRank('x'), -1);
+    });
+
+    it('identifies windows below threshold', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('c');
+        list.onFocus('d');
+        // Ranks: ['d','c','b','a']. Top 3 = d,c,b. Below = a.
+        const below = list.windowsBelowRank(3);
+        assertDeepEqual(below, ['a']);
+    });
+
+    it('returns empty when all within threshold', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        const below = list.windowsBelowRank(3);
+        assertDeepEqual(below, []);
+    });
+
+    it('returns lowest-ranked window', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('c');
+        assertEqual(list.getLowestRanked(), 'a');
+    });
+
+    it('returns lowest-ranked excluding a set', () => {
+        const list = new FocusRankList();
+        list.onFocus('a');
+        list.onFocus('b');
+        list.onFocus('c');
+        assertEqual(list.getLowestRanked(new Set(['a'])), 'b');
+    });
+});
+
+import System from 'system';
+const allPassed = printResults();
+if (!allPassed) System.exit(1);
